#define BLOCK_SIZE 16

const float amb_temp = 80.0f;

__kernel void hotspot(
    const int num_iterations,
    const __global float* power,
    const __global float* temp,
    __global float* result,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int blockCols = (col + borderCols - 1) / BLOCK_SIZE;
    int blockRows = (row + borderRows - 1) / BLOCK_SIZE;

    int r_start = get_group_id(1) * BLOCK_SIZE;
    int c_start = get_group_id(0) * BLOCK_SIZE;
    int r_end = r_start + BLOCK_SIZE > row ? row : r_start + BLOCK_SIZE;
    int c_end = c_start + BLOCK_SIZE > col ? col : c_start + BLOCK_SIZE;

    int is_border_block = (r_start == 0) || (c_start == 0) || (r_end == row) || (c_end == col);

    const __global float* in_ptr = temp;
    __global float* out_ptr = result;

    for (int i = 0; i < num_iterations; i++) {
        for (int r = r_start; r < r_end; r++) {
            for (int c = c_start; c < c_end; c++) {
                float delta;
                int idx = r * col + c;

                if (is_border_block) {
                    if ((r == 0) && (c == 0)) {
                        delta = Cap_1 * (power[0] +
                            (in_ptr[1] - in_ptr[0]) * Rx_1 +
                            (in_ptr[col] - in_ptr[0]) * Ry_1 +
                            (amb_temp - in_ptr[0]) * Rz_1);
                    }
                    else if ((r == 0) && (c == col - 1)) {
                        delta = Cap_1 * (power[c] +
                            (in_ptr[c - 1] - in_ptr[c]) * Rx_1 +
                            (in_ptr[c + col] - in_ptr[c]) * Ry_1 +
                            (amb_temp - in_ptr[c]) * Rz_1);
                    }
                    else if ((r == row - 1) && (c == col - 1)) {
                        delta = Cap_1 * (power[idx] +
                            (in_ptr[idx - 1] - in_ptr[idx]) * Rx_1 +
                            (in_ptr[(r - 1) * col + c] - in_ptr[idx]) * Ry_1 +
                            (amb_temp - in_ptr[idx]) * Rz_1);
                    }
                    else if ((r == row - 1) && (c == 0)) {
                        delta = Cap_1 * (power[r * col] +
                            (in_ptr[r * col + 1] - in_ptr[r * col]) * Rx_1 +
                            (in_ptr[(r - 1) * col] - in_ptr[r * col]) * Ry_1 +
                            (amb_temp - in_ptr[r * col]) * Rz_1);
                    }
                    else if (r == 0) {
                        delta = Cap_1 * (power[c] +
                            (in_ptr[c + 1] + in_ptr[c - 1] - 2.0f * in_ptr[c]) * Rx_1 +
                            (in_ptr[col + c] - in_ptr[c]) * Ry_1 +
                            (amb_temp - in_ptr[c]) * Rz_1);
                    }
                    else if (c == col - 1) {
                        delta = Cap_1 * (power[idx] +
                            (in_ptr[(r + 1) * col + c] + in_ptr[(r - 1) * col + c] - 2.0f * in_ptr[idx]) * Ry_1 +
                            (in_ptr[idx - 1] - in_ptr[idx]) * Rx_1 +
                            (amb_temp - in_ptr[idx]) * Rz_1);
                    }
                    else if (r == row - 1) {
                        delta = Cap_1 * (power[idx] +
                            (in_ptr[idx + 1] + in_ptr[idx - 1] - 2.0f * in_ptr[idx]) * Rx_1 +
                            (in_ptr[(r - 1) * col + c] - in_ptr[idx]) * Ry_1 +
                            (amb_temp - in_ptr[idx]) * Rz_1);
                    }
                    else if (c == 0) {
                        delta = Cap_1 * (power[r * col] +
                            (in_ptr[(r + 1) * col] + in_ptr[(r - 1) * col] - 2.0f * in_ptr[r * col]) * Ry_1 +
                            (in_ptr[r * col + 1] - in_ptr[r * col]) * Rx_1 +
                            (amb_temp - in_ptr[r * col]) * Rz_1);
                    }
                    else {
                        delta = Cap_1 * (power[idx] +
                            (in_ptr[(r + 1) * col + c] + in_ptr[(r - 1) * col + c] - 2.0f * in_ptr[idx]) * Ry_1 +
                            (in_ptr[idx + 1] + in_ptr[idx - 1] - 2.0f * in_ptr[idx]) * Rx_1 +
                            (amb_temp - in_ptr[idx]) * Rz_1);
                    }
                } else {
                    delta = Cap_1 * (power[idx] +
                        (in_ptr[(r + 1) * col + c] + in_ptr[(r - 1) * col + c] - 2.0f * in_ptr[idx]) * Ry_1 +
                        (in_ptr[idx + 1] + in_ptr[idx - 1] - 2.0f * in_ptr[idx]) * Rx_1 +
                        (amb_temp - in_ptr[idx]) * Rz_1);
                }

                out_ptr[idx] = in_ptr[idx] + delta;
            }
        }

        const __global float* tmp_in = in_ptr;
        in_ptr = out_ptr;
        out_ptr = tmp_in;
    }
}
